// Pega input e output
const input = $('executarFluxo').first().json.input;
const output = $('executarFluxo').first().json.output;
const llmModel = $('executarFluxo').first().json.llmModel;


// Estima tokens (1.5 tokens por palavra em português)
const estimateTokens = (text) => {
  if (!text) return 0;
  const words = text.split(/\s+/).length;
  return Math.ceil(words * 1.5);
};

const inputTokens = estimateTokens(input);
const outputTokens = estimateTokens(output);
const totalTokens = inputTokens + outputTokens;

// Preços GPT-4o (por 1M tokens)
const precoInput = $input.first().json.input_price;   // $2.50 por 1M input
const precoOutput = $input.first().json.output_price; // $10.00 por 1M output

// Cotação dólar
const dolar = $input.first().json.dolar;

// Calcula custo
const custoUSD = ((inputTokens / 1_000_000) * precoInput) + ((outputTokens / 1_000_000) * precoOutput);
const custoBRL = custoUSD * dolar;

return {
  output: output,
  input_tokens: inputTokens,
  output_tokens: outputTokens,
  total_tokens: totalTokens,
  model: llmModel,
  custo_usd: Number(custoUSD.toFixed(8)),
  custo_brl: Number(custoBRL.toFixed(6))
};

